\title{Multi-Strategy GraphRAG for Financial Institutions: Security, Grounding, and Token Economy}

\author[inst1]{Anonymous Author\corref{cor1}}
\cortext[cor1]{Corresponding author}
\ead{anonymous@institution.edu}
